import { Injectable } from '@angular/core';
import { Router } from '@angular/router';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import { CommonHttpModule } from '../providers/commonHttpModule';
import { LoginResponse } from './login/login.model';

@Injectable({ providedIn: 'root' })
export class AuthService {
    constructor(private httpService: CommonHttpModule, private router: Router,) { }

    login(username: string, password: string): Observable<LoginResponse> {
        return this.httpService.post<any>(`auth/token`, { username, password }).pipe(
            map(response => {
                sessionStorage.setItem("name", response.name);
                sessionStorage.setItem("role", response.role_name);
                sessionStorage.setItem("roleId", response.role_id);
                return response;
            })
        );
    }
    sendOtp(otp: Number, uuid: string): Observable<any> {
        return this.httpService.post<any>(`otp/validate`, { otp, uuid }).pipe(
            map(response => {
                return response;
            })
        );
    }
    reSendOtp(): Observable<any> {
        return this.httpService.post<any>(`otp/resend`, null).pipe(
            map(response => {
                return response;
            })
        );
    }
    sendOtpfromforget(username: string, otp: Number, uuid: string, new_password: string): Observable<any> {
        return this.httpService.post<any>(`password-reset/validate-otp`, { username, otp, uuid, new_password }).pipe(
            map(response => {
                return response;
            })
        );
    }
    validateLink(passwordreset_token: string | null): Observable<any> {
        return this.httpService.post<any>(`validate-link`, { passwordreset_token }).pipe(
            map(response => {
                return response;
            })
        );
    }

    getResetOtp(token: string): Observable<any> {
        return this.httpService.post<any>(`password-reset/get-otp`, { token }).pipe(
            map(response => {
                return response;
            })
        );
    }

    updateOtpfromforget(username: string, passwordreset_token: string, new_password: string): Observable<any> {
        return this.httpService.post<any>(`password-reset`, { username, new_password, passwordreset_token }).pipe(
            map(response => {
                return response;
            })
        );
    }

    forgotpassword(username: string): Observable<any> {
        return this.httpService.post<any>('request-password-reset', { username }).pipe(
            map(response => {
                return response;
            })
        )
    }

    disbursementLogin(loginData: { email: string, pda_token: string }): Observable<any> {
        return this.httpService.post<any>('validate_pda_link', loginData).pipe(
            map(response => {
                return response;
            })
        );
    }

    validateDisbursementOtp(otpData: { uuid: string, otp: number }): Observable<any> {
        return this.httpService.post<any>('validate_pda_link_otp', otpData).pipe(
            map(response => {
                return response;
            })
        );
    }

    requestPasswordResetOTP(token: string): Observable<any> {
        return this.httpService.post<any>('password-reset/send-otp', { token }).pipe(
            map(response => {
                return response;
            })
        );
    }

    resetPasswordWithOTP(payload: { token: string, uuid: string, otp: number, newPassword: string }): Observable<any> {
        return this.httpService.post<any>('password-reset/verify-otp', payload).pipe(
            map(response => {
                return response;
            })
        );
    }

    changePassword(username: string, currentPassword: string, newPassword: string): Observable<any> {
        return this.httpService.post<any>('change-password', {
            username,
            old_password: currentPassword,
            new_password: newPassword
        }).pipe(
            map(response => {
                return response;
            })
        );
    }

    passwordExpired(username: string, currentPassword: string, newPassword: string): Observable<any> {
        return this.httpService.post<any>('expired-password-reset', {
            username,
            old_password: currentPassword,
            new_password: newPassword
        }).pipe(
            map(response => {
                return response;
            })
        );
    }

    logout(): Observable<any> {
        return this.httpService.post<any>('auth/logout', {}).pipe(
            map(response => {
                return response;
            })
        );
    }


}